222 CmpInst::Predicate ConstantRange::getEquivalentPredWithFlippedSignedness(
223     CmpInst::Predicate Pred, const ConstantRange &CR1,
224     const ConstantRange &CR2) {
225   assert(CmpInst::isIntPredicate(Pred) && CmpInst::isRelational(Pred) &&
226          "Only for relational integer predicates!");
227 
228   CmpInst::Predicate FlippedSignednessPred =
229       ICmpInst::getFlippedSignednessPredicate(Pred);
230 
231   if (areInsensitiveToSignednessOfICmpPredicate(CR1, CR2))
232     return FlippedSignednessPred;
233 
234   if (areInsensitiveToSignednessOfInvertedICmpPredicate(CR1, CR2))
235     return CmpInst::getInversePredicate(FlippedSignednessPred);
236 
237   return CmpInst::Predicate::BAD_ICMP_PREDICATE;
