240 void ConstantRange::getEquivalentICmp(CmpInst::Predicate &Pred,
241                                       APInt &RHS, APInt &Offset) const {
242   Offset = APInt(getBitWidth(), 0);
243   if (isFullSet() || isEmptySet()) {
244     Pred = isEmptySet() ? CmpInst::ICMP_ULT : CmpInst::ICMP_UGE;
245     RHS = APInt(getBitWidth(), 0);
246   } else if (auto *OnlyElt = getSingleElement()) {
247     Pred = CmpInst::ICMP_EQ;
248     RHS = *OnlyElt;
249   } else if (auto *OnlyMissingElt = getSingleMissingElement()) {
250     Pred = CmpInst::ICMP_NE;
251     RHS = *OnlyMissingElt;
252   } else if (getLower().isMinSignedValue() || getLower().isMinValue()) {
253     Pred =
254         getLower().isMinSignedValue() ? CmpInst::ICMP_SLT : CmpInst::ICMP_ULT;
255     RHS = getUpper();
256   } else if (getUpper().isMinSignedValue() || getUpper().isMinValue()) {
257     Pred =
258         getUpper().isMinSignedValue() ? CmpInst::ICMP_SGE : CmpInst::ICMP_UGE;
259     RHS = getLower();
260   } else {
261     Pred = CmpInst::ICMP_ULT;
262     RHS = getUpper() - getLower();
263     Offset = -getLower();
264   }
265 
266   assert(ConstantRange::makeExactICmpRegion(Pred, RHS) == add(Offset) &&
267          "Bad result!");
268 }
