270 bool ConstantRange::getEquivalentICmp(CmpInst::Predicate &Pred,
271                                       APInt &RHS) const {
272   APInt Offset;
273   getEquivalentICmp(Pred, RHS, Offset);
274   return Offset.isZero();
275 }
