277 bool ConstantRange::icmp(CmpInst::Predicate Pred,
278                          const ConstantRange &Other) const {
279   if (isEmptySet() || Other.isEmptySet())
280     return true;
281 
282   switch (Pred) {
283   case CmpInst::ICMP_EQ:
284     if (const APInt *L = getSingleElement())
285       if (const APInt *R = Other.getSingleElement())
286         return *L == *R;
287     return false;
288   case CmpInst::ICMP_NE:
289     return inverse().contains(Other);
290   case CmpInst::ICMP_ULT:
291     return getUnsignedMax().ult(Other.getUnsignedMin());
292   case CmpInst::ICMP_ULE:
293     return getUnsignedMax().ule(Other.getUnsignedMin());
294   case CmpInst::ICMP_UGT:
295     return getUnsignedMin().ugt(Other.getUnsignedMax());
296   case CmpInst::ICMP_UGE:
297     return getUnsignedMin().uge(Other.getUnsignedMax());
298   case CmpInst::ICMP_SLT:
299     return getSignedMax().slt(Other.getSignedMin());
300   case CmpInst::ICMP_SLE:
301     return getSignedMax().sle(Other.getSignedMin());
302   case CmpInst::ICMP_SGT:
303     return getSignedMin().sgt(Other.getSignedMax());
304   case CmpInst::ICMP_SGE:
305     return getSignedMin().sge(Other.getSignedMax());
306   default:
307     llvm_unreachable("Invalid ICmp predicate");
308   }
309 }
