10472 bool llvm::collectPossibleValues(const Value *V,
10473                                  SmallPtrSetImpl<const Constant *> &Constants,
10474                                  unsigned MaxCount, bool AllowUndefOrPoison) {
10475   SmallPtrSet<const Instruction *, 8> Visited;
10476   SmallVector<const Instruction *, 8> Worklist;
10477   auto Push = [&](const Value *V) -> bool {
10478     Constant *C;
10479     if (match(const_cast<Value *>(V), m_ImmConstant(C))) {
10480       if (!AllowUndefOrPoison && !isGuaranteedNotToBeUndefOrPoison(C))
10481         return false;
10482       // Check existence first to avoid unnecessary allocations.
10483       if (Constants.contains(C))
10484         return true;
10485       if (Constants.size() == MaxCount)
10486         return false;
10487       Constants.insert(C);
10488       return true;
10489     }
10490 
10491     if (auto *Inst = dyn_cast<Instruction>(V)) {
10492       if (Visited.insert(Inst).second)
10493         Worklist.push_back(Inst);
10494       return true;
10495     }
10496     return false;
10497   };
10498   if (!Push(V))
10499     return false;
10500   while (!Worklist.empty()) {
10501     const Instruction *CurInst = Worklist.pop_back_val();
10502     switch (CurInst->getOpcode()) {
10503     case Instruction::Select:
10504       if (!Push(CurInst->getOperand(1)))
10505         return false;
10506       if (!Push(CurInst->getOperand(2)))
10507         return false;
10508       break;
10509     case Instruction::PHI:
10510       for (Value *IncomingValue : cast<PHINode>(CurInst)->incoming_values()) {
10511         // Fast path for recurrence PHI.
10512         if (IncomingValue == CurInst)
10513           continue;
10514         if (!Push(IncomingValue))
10515           return false;
10516       }
10517       break;
10518     default:
10519       return false;
10520     }
10521   }
10522   return true;
10523 }
