10322 void llvm::findValuesAffectedByCondition(
10323     Value *Cond, bool IsAssume, function_ref<void(Value *)> InsertAffected) {
10324   auto AddAffected = [&InsertAffected](Value *V) {
10325     addValueAffectedByCondition(V, InsertAffected);
10326   };
10327 
10328   auto AddCmpOperands = [&AddAffected, IsAssume](Value *LHS, Value *RHS) {
10329     if (IsAssume) {
10330       AddAffected(LHS);
10331       AddAffected(RHS);
10332     } else if (match(RHS, m_Constant()))
10333       AddAffected(LHS);
10334   };
10335 
10336   SmallVector<Value *, 8> Worklist;
10337   SmallPtrSet<Value *, 8> Visited;
10338   Worklist.push_back(Cond);
10339   while (!Worklist.empty()) {
10340     Value *V = Worklist.pop_back_val();
10341     if (!Visited.insert(V).second)
10342       continue;
10343 
10344     CmpPredicate Pred;
10345     Value *A, *B, *X;
10346 
10347     if (IsAssume) {
10348       AddAffected(V);
10349       if (match(V, m_Not(m_Value(X))))
10350         AddAffected(X);
10351     }
10352 
10353     if (match(V, m_LogicalOp(m_Value(A), m_Value(B)))) {
10354       // assume(A && B) is split to -> assume(A); assume(B);
10355       // assume(!(A || B)) is split to -> assume(!A); assume(!B);
10356       // Finally, assume(A || B) / assume(!(A && B)) generally don't provide
10357       // enough information to be worth handling (intersection of information as
10358       // opposed to union).
10359       if (!IsAssume) {
10360         Worklist.push_back(A);
10361         Worklist.push_back(B);
10362       }
10363     } else if (match(V, m_ICmp(Pred, m_Value(A), m_Value(B)))) {
10364       bool HasRHSC = match(B, m_ConstantInt());
10365       if (ICmpInst::isEquality(Pred)) {
10366         AddAffected(A);
10367         if (IsAssume)
10368           AddAffected(B);
10369         if (HasRHSC) {
10370           Value *Y;
10371           // (X << C) or (X >>_s C) or (X >>_u C).
10372           if (match(A, m_Shift(m_Value(X), m_ConstantInt())))
10373             AddAffected(X);
10374           // (X & C) or (X | C).
10375           else if (match(A, m_And(m_Value(X), m_Value(Y))) ||
10376                    match(A, m_Or(m_Value(X), m_Value(Y)))) {
10377             AddAffected(X);
10378             AddAffected(Y);
10379           }
10380           // X - Y
10381           else if (match(A, m_Sub(m_Value(X), m_Value(Y)))) {
10382             AddAffected(X);
10383             AddAffected(Y);
10384           }
10385         }
10386       } else {
10387         AddCmpOperands(A, B);
10388         if (HasRHSC) {
10389           // Handle (A + C1) u< C2, which is the canonical form of
10390           // A > C3 && A < C4.
10391           if (match(A, m_AddLike(m_Value(X), m_ConstantInt())))
10392             AddAffected(X);
10393 
10394           if (ICmpInst::isUnsigned(Pred)) {
10395             Value *Y;
10396             // X & Y u> C    -> X >u C && Y >u C
10397             // X | Y u< C    -> X u< C && Y u< C
10398             // X nuw+ Y u< C -> X u< C && Y u< C
10399             if (match(A, m_And(m_Value(X), m_Value(Y))) ||
10400                 match(A, m_Or(m_Value(X), m_Value(Y))) ||
10401                 match(A, m_NUWAdd(m_Value(X), m_Value(Y)))) {
10402               AddAffected(X);
10403               AddAffected(Y);
10404             }
10405             // X nuw- Y u> C -> X u> C
10406             if (match(A, m_NUWSub(m_Value(X), m_Value())))
10407               AddAffected(X);
10408           }
10409         }
10410 
10411         // Handle icmp slt/sgt (bitcast X to int), 0/-1, which is supported
10412         // by computeKnownFPClass().
10413         if (match(A, m_ElementWiseBitCast(m_Value(X)))) {
10414           if (Pred == ICmpInst::ICMP_SLT && match(B, m_Zero()))
10415             InsertAffected(X);
10416           else if (Pred == ICmpInst::ICMP_SGT && match(B, m_AllOnes()))
10417             InsertAffected(X);
10418         }
10419       }
10420 
10421       if (HasRHSC && match(A, m_Intrinsic<Intrinsic::ctpop>(m_Value(X))))
10422         AddAffected(X);
10423     } else if (match(V, m_FCmp(Pred, m_Value(A), m_Value(B)))) {
10424       AddCmpOperands(A, B);
10425 
10426       // fcmp fneg(x), y
10427       // fcmp fabs(x), y
10428       // fcmp fneg(fabs(x)), y
10429       if (match(A, m_FNeg(m_Value(A))))
10430         AddAffected(A);
10431       if (match(A, m_FAbs(m_Value(A))))
10432         AddAffected(A);
10433 
10434     } else if (match(V, m_Intrinsic<Intrinsic::is_fpclass>(m_Value(A),
10435                                                            m_Value()))) {
10436       // Handle patterns that computeKnownFPClass() support.
10437       AddAffected(A);
10438     } else if (!IsAssume && match(V, m_Trunc(m_Value(X)))) {
10439       // Assume is checked here as X is already added above for assumes in
10440       // addValueAffectedByCondition
10441       AddAffected(X);
10442     } else if (!IsAssume && match(V, m_Not(m_Value(X)))) {
10443       // Assume is checked here to avoid issues with ephemeral values
10444       Worklist.push_back(X);
10445     }
10446   }
10447 }
