311 /// Exact mul nuw region for single element RHS.
312 static ConstantRange makeExactMulNUWRegion(const APInt &V) {
313   unsigned BitWidth = V.getBitWidth();
314   if (V == 0)
315     return ConstantRange::getFull(V.getBitWidth());
316 
317   return ConstantRange::getNonEmpty(
318       APIntOps::RoundingUDiv(APInt::getMinValue(BitWidth), V,
319                              APInt::Rounding::UP),
320       APIntOps::RoundingUDiv(APInt::getMaxValue(BitWidth), V,
321                              APInt::Rounding::DOWN) + 1);
322 }
323 
324 /// Exact mul nsw region for single element RHS.
325 static ConstantRange makeExactMulNSWRegion(const APInt &V) {
326   // Handle 0 and -1 separately to avoid division by zero or overflow.
327   unsigned BitWidth = V.getBitWidth();
328   if (V == 0)
329     return ConstantRange::getFull(BitWidth);
330 
331   APInt MinValue = APInt::getSignedMinValue(BitWidth);
332   APInt MaxValue = APInt::getSignedMaxValue(BitWidth);
333   // e.g. Returning [-127, 127], represented as [-127, -128).
334   if (V.isAllOnes())
335     return ConstantRange(-MaxValue, MinValue);
336 
337   APInt Lower, Upper;
338   if (V.isNegative()) {
339     Lower = APIntOps::RoundingSDiv(MaxValue, V, APInt::Rounding::UP);
340     Upper = APIntOps::RoundingSDiv(MinValue, V, APInt::Rounding::DOWN);
341   } else {
342     Lower = APIntOps::RoundingSDiv(MinValue, V, APInt::Rounding::UP);
343     Upper = APIntOps::RoundingSDiv(MaxValue, V, APInt::Rounding::DOWN);
344   }
345   return ConstantRange::getNonEmpty(Lower, Upper + 1);
346 }
