348 ConstantRange
349 ConstantRange::makeGuaranteedNoWrapRegion(Instruction::BinaryOps BinOp,
350                                           const ConstantRange &Other,
351                                           unsigned NoWrapKind) {
352   using OBO = OverflowingBinaryOperator;
353 
354   assert(Instruction::isBinaryOp(BinOp) && "Binary operators only!");
355 
356   assert((NoWrapKind == OBO::NoSignedWrap ||
357           NoWrapKind == OBO::NoUnsignedWrap) &&
358          "NoWrapKind invalid!");
359 
360   bool Unsigned = NoWrapKind == OBO::NoUnsignedWrap;
361   unsigned BitWidth = Other.getBitWidth();
362 
363   switch (BinOp) {
364   default:
365     llvm_unreachable("Unsupported binary op");
366 
367   case Instruction::Add: {
368     if (Unsigned)
369       return getNonEmpty(APInt::getZero(BitWidth), -Other.getUnsignedMax());
370 
371     APInt SignedMinVal = APInt::getSignedMinValue(BitWidth);
372     APInt SMin = Other.getSignedMin(), SMax = Other.getSignedMax();
373     return getNonEmpty(
374         SMin.isNegative() ? SignedMinVal - SMin : SignedMinVal,
375         SMax.isStrictlyPositive() ? SignedMinVal - SMax : SignedMinVal);
376   }
377 
378   case Instruction::Sub: {
379     if (Unsigned)
380       return getNonEmpty(Other.getUnsignedMax(), APInt::getMinValue(BitWidth));
381 
382     APInt SignedMinVal = APInt::getSignedMinValue(BitWidth);
383     APInt SMin = Other.getSignedMin(), SMax = Other.getSignedMax();
384     return getNonEmpty(
385         SMax.isStrictlyPositive() ? SignedMinVal + SMax : SignedMinVal,
386         SMin.isNegative() ? SignedMinVal + SMin : SignedMinVal);
387   }
388 
389   case Instruction::Mul:
390     if (Unsigned)
391       return makeExactMulNUWRegion(Other.getUnsignedMax());
392 
393     // Avoid one makeExactMulNSWRegion() call for the common case of constants.
394     if (const APInt *C = Other.getSingleElement())
395       return makeExactMulNSWRegion(*C);
396 
397     return makeExactMulNSWRegion(Other.getSignedMin())
398         .intersectWith(makeExactMulNSWRegion(Other.getSignedMax()));
399 
400   case Instruction::Shl: {
401     // For given range of shift amounts, if we ignore all illegal shift amounts
402     // (that always produce poison), what shift amount range is left?
403     ConstantRange ShAmt = Other.intersectWith(
404         ConstantRange(APInt(BitWidth, 0), APInt(BitWidth, (BitWidth - 1) + 1)));
405     if (ShAmt.isEmptySet()) {
406       // If the entire range of shift amounts is already poison-producing,
407       // then we can freely add more poison-producing flags ontop of that.
408       return getFull(BitWidth);
409     }
410     // There are some legal shift amounts, we can compute conservatively-correct
411     // range of no-wrap inputs. Note that by now we have clamped the ShAmtUMax
412     // to be at most bitwidth-1, which results in most conservative range.
413     APInt ShAmtUMax = ShAmt.getUnsignedMax();
414     if (Unsigned)
415       return getNonEmpty(APInt::getZero(BitWidth),
416                          APInt::getMaxValue(BitWidth).lshr(ShAmtUMax) + 1);
417     return getNonEmpty(APInt::getSignedMinValue(BitWidth).ashr(ShAmtUMax),
418                        APInt::getSignedMaxValue(BitWidth).ashr(ShAmtUMax) + 1);
419   }
420   }
421 }
422 
423 ConstantRange ConstantRange::makeExactNoWrapRegion(Instruction::BinaryOps BinOp,
424                                                    const APInt &Other,
425                                                    unsigned NoWrapKind) {
426   // makeGuaranteedNoWrapRegion() is exact for single-element ranges, as
427   // "for all" and "for any" coincide in this case.
428   return makeGuaranteedNoWrapRegion(BinOp, ConstantRange(Other), NoWrapKind);
