110 ConstantRange ConstantRange::makeAllowedICmpRegion(CmpPredicate Pred,
111                                                    const ConstantRange &CR) {
112   if (CR.isEmptySet())
113     return CR;
114 
115   uint32_t W = CR.getBitWidth();
116   ConstantRange Result = getFull(W);
117   switch (Pred) {
118   default:
119     llvm_unreachable("Invalid ICmp predicate to makeAllowedICmpRegion()");
120   case CmpInst::ICMP_EQ:
121     return CR;
122   case CmpInst::ICMP_NE:
123     if (CR.isSingleElement())
124       return ConstantRange(CR.getUpper(), CR.getLower());
125     return getFull(W);
126   case CmpInst::ICMP_ULT: {
127     APInt UMax(CR.getUnsignedMax());
128     if (UMax.isMinValue())
129       return getEmpty(W);
130     Result = ConstantRange(APInt::getMinValue(W), std::move(UMax));
131     if (!Pred.hasSameSign())
132       return Result;
133   }
134     // For samesign, intersect with signed range.
135     LLVM_FALLTHROUGH;
136   case CmpInst::ICMP_SLT: {
137     APInt SMax(CR.getSignedMax());
138     if (SMax.isMinSignedValue())
139       return getEmpty(W);
140     return Result.intersectWith(
141         ConstantRange(APInt::getSignedMinValue(W), std::move(SMax)));
142   }
143   case CmpInst::ICMP_ULE: {
144     Result = getNonEmpty(APInt::getMinValue(W), CR.getUnsignedMax() + 1);
145     if (!Pred.hasSameSign())
146       return Result;
147   }
148     // For samesign, intersect with signed range.
149     LLVM_FALLTHROUGH;
150   case CmpInst::ICMP_SLE:
151     return Result.intersectWith(
152         getNonEmpty(APInt::getSignedMinValue(W), CR.getSignedMax() + 1));
153   case CmpInst::ICMP_UGT: {
154     APInt UMin(CR.getUnsignedMin());
155     if (UMin.isMaxValue())
156       return getEmpty(W);
157     Result = ConstantRange(std::move(UMin) + 1, APInt::getZero(W));
158     if (!Pred.hasSameSign())
159       return Result;
160   }
161     // For samesign, intersect with signed range.
162     LLVM_FALLTHROUGH;
163   case CmpInst::ICMP_SGT: {
164     APInt SMin(CR.getSignedMin());
165     if (SMin.isMaxSignedValue())
166       return getEmpty(W);
167     return Result.intersectWith(
168         ConstantRange(std::move(SMin) + 1, APInt::getSignedMinValue(W)));
169   }
170   case CmpInst::ICMP_UGE: {
171     Result = getNonEmpty(CR.getUnsignedMin(), APInt::getZero(W));
172     if (!Pred.hasSameSign())
173       return Result;
174   }
175     // For samesign, intersect with signed range.
176     LLVM_FALLTHROUGH;
177   case CmpInst::ICMP_SGE:
178     return Result.intersectWith(
